    const matchFactionByText = (text) => {
      if (!text) return null;
      return factions.find((item) => [item.name, ...item.aliases].some((alias) => text.indexOf(alias) !== -1)) || null;
    };

    const explicitFaction = [identityFaction, currentSituation, navigationInfo, directCtx]
      .map(matchFactionByText)
      .find(Boolean) || null;

    const domain =
      (explicitFaction ? domains.find((item) => item.name === explicitFaction.domain) : null) ||
      matchDomainByText(currentSituation) ||
      matchDomainByText(navigationInfo) ||
      matchDomainByText(directCtx) ||
      domains.find((item) => item.name === derivedDomainName);

    const factionTexts = [
      identityFaction,
      currentSituation,
      navigationInfo,
      directCtx,
      derivedFactionName,
    ].filter(Boolean);

    let faction = factionTexts.map(matchFactionByText).find(Boolean) || null;

    if (!faction && domain) {
      const defaultByDomain = {
        '神州': '忘机剑庐',
        '东苍': '苍木龙吟阁',
        '南炎': '昭明破阵宗',
        '西庚': '藏锋敛锷山庄',
        '北冥与幽界': '坐忘冥海阁'
      };
      faction = factions.find((item) => item.name === defaultByDomain[domain.name]) || null;
    }

    return { faction };
  })();
